const axios = require('axios');
const fs = require('fs');

// Replace with your LLM API endpoint
const apiEndpoint = 'https://api.llm.com/generate';

// User input prompt
let userInput;

process.stdin.on('data', data => {
    userInput += data.toString();
});

process.stdin.on('end', async () => {
    const prompt = userInput.trim();

    try {
        // Send request to LLM API with user's prompt
        const response = await axios.post(apiEndpoint, { prompt });

        // Get the generated code from the response
        const generatedCode = response.data.code;

        // Execute the generated code in a new Node.js process
        exec(genrCode(generatedCode));

    } catch (error) {
        console.error(error);
    }
});

// Function to execute the generated code in a new Node.js process
function genrCode(code) {
    const executableCode = `
        const fs = require('fs');
        const { spawnSync } = require('child_process');

        try {
            ${code}
        } catch (error) {
            console.error(error);
            process.exit(1);
        }
    `;

    return executableCode;
}

// Function to execute a command in the terminal
function exec(command) {
    const { spawnSync } = require('child_process');
    const result = spawnSync(command, { shell: true });
    if (result.status !== 0) {
        console.error(`Error executing command: ${command}`);
    }
}